# Python 3.11+
"""Rejection policies ‚ÄĒ the seam that decides what happens when the bounded
queue is FULL at submit() time.

ūüéôÔłŹ "The pool doesn't hardcode 'block the caller'. It asks a RejectionPolicy.
That's exactly Java's RejectedExecutionHandler ‚ÄĒ block, abort, run-on-caller, or
discard. Swapping the back-pressure behaviour is a new class, zero pool changes."
"""

from abc import ABC, abstractmethod

from models import BoundedBlockingQueue, Future, RejectedError, Task


class RejectionPolicy(ABC):
    # ‚ĒÄ‚ĒÄ WHY THIS CLASS ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ
    # The abstraction ThreadPool depends on (Dependency Inversion). Called only
    # when a non-blocking put failed because the queue was full.
    @abstractmethod
    def on_rejected(self, task: Task, queue: BoundedBlockingQueue, future: Future) -> None:
        """Handle a task that couldn't be enqueued. May block, raise, or drop."""
        raise NotImplementedError


class BlockPolicy(RejectionPolicy):
    """Back-pressure: block the submitting thread until the queue has room. (Default.)"""

    def on_rejected(self, task, queue, future):
        queue.put(task, block=True)                  # waits on not_full, then enqueues


class AbortPolicy(RejectionPolicy):
    """Fail fast: raise a typed error so the caller knows the pool is saturated."""

    def on_rejected(self, task, queue, future):
        raise RejectedError("task queue is full; pool is saturated")


class CallerRunsPolicy(RejectionPolicy):
    """Throttle: run the task on the submitting thread, slowing the producer naturally."""

    def on_rejected(self, task, queue, future):
        task.run()                                   # fills `future` synchronously


class DiscardPolicy(RejectionPolicy):
    """Shed load: silently drop the task. Its future is cancelled so result() is honest."""

    def on_rejected(self, task, queue, future):
        future.cancel()

